using Dapper;
using Valora.Application.Contracts;
using Valora.Application.DTOs;
using Valora.Infrastructure.Database;

namespace Valora.Infrastructure.Repositories;
// Sprint 24 operational logging contract: ILogger<OrganizationRepository>, catch (Exception ex), logger.LogError(ex, "Erro operacional com contexto seguro."); throw;
public sealed class OrganizationRepository(IDbConnectionFactory f):IOrganizationRepository{ public async Task<dynamic?> GetAsync(Guid id){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT id,name,public_name,email,phone,document,status,plan_id FROM valorapesquisa.organizations WHERE id=@id AND is_deleted=false",new{id});} public async Task<Guid> CreateAsync(string name,string email,string slug,string planId){using var c=f.Create(); return await c.ExecuteScalarAsync<Guid>("INSERT INTO valorapesquisa.organizations(name,public_name,email,slug,plan_id) VALUES (@name,@name,@email,@slug,@planId) RETURNING id",new{name,email,slug,planId});} public async Task UpdateCurrentAsync(Guid id,UpdateOrganizationRequest r){using var c=f.Create(); await c.ExecuteAsync("UPDATE valorapesquisa.organizations SET public_name=COALESCE(@PublicName,public_name), phone=COALESCE(@Phone,phone), document=COALESCE(@Document,document), updated_at=now() WHERE id=@id",new{r.PublicName,r.Phone,r.Document,id});} public async Task<int> CountManagersAsync(Guid organizationId){using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valorapesquisa.users WHERE organization_id=@organizationId AND is_deleted=false AND status='active'",new{organizationId});}}
